/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(SalesAgreementCreate, SalesAgreementHeader), FormDataSourceEventType::Activated)]
public static void SalesAgreementHeader_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormDataSource      SalesAgreementHeader_ds   = sender.formrun().dataSource(formDataSourceStr(SalesAgreementCreate, SalesAgreementHeader)) as FormDataSource;
    SalesAgreementHeader_ds.object(fieldNum(SalesAgreementHeader, DefaultAgreementLineEffectiveDate)).mandatory(true);
    SalesAgreementHeader_ds.object(fieldNum(SalesAgreementHeader, DefaultAgreementLineExpirationDate)).mandatory(true);
}

//NS, DLT ,05/03/2025  Only Trading custmores should be available for booking contracts

/// <summary>
/// this method Handles the lookup event for the PurchAgreementHeader_CustAccount1 control.
/// This method sets up a customized lookup for custmores account information
/// </summary>
/// <param name="sender">FormControl sender</param>
/// <param name="e">FormControlEventArgs e</param>
[FormControlEventHandler(formControlStr(SalesAgreementCreate, SalesAgreementHeader_CustAccount), FormControlEventType::Lookup)]
public static void SalesAgreementHeader_CustAccount_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(ETGCustLookupView),sender);
        Query                   q   = new Query();
        QueryBuildDataSource    qbds;

        qbds   = q.addDataSource(tableNum(ETGCustLookupView));

        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView,AccountNum));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, Name));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, NameAlias));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, City));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, State));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, CountryRegionId));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, ZipCode));
        sysTableLookup.addLookupfield(fieldNum(ETGCustLookupView, OurAccountNum));
        SysTableLookup.parmQuery(q);
        SysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;
        ce.CancelSuperCall();
    }
}

