/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesAgreement, ContainerDetailsButton), FormControlEventType::Clicked)]
public static void ContainerDetailsButton_OnClicked(FormControl sender, FormControlEventArgs e)
{
    SalesAgreementHeader salesAgreementHeader;
    FormRun formRun = sender.formRun();
    FormDataSource salesAgreementHeader_ds = formRun.dataSource(formDataSourceStr(SalesAgreement, SalesAgreementHeader));
    salesAgreementHeader = salesAgreementHeader_ds.cursor();

    Args args = new Args(formStr(ETG_BOLCarrierSalesContractForm));
    args.record(salesAgreementHeader);
    args.parm(salesAgreementHeader.SalesNumberSequence);

    new MenuFunction(menuItemDisplayStr(ETG_BOLCarrierSalesContractDisplay),MenuItemType::Display).run(args);
}
